#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using block_type = std::uint64_t;
    hexi::block_allocator<block_type, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===" << std::endl;
    std::cout << "Block size: " << sizeof(block_type) << " bytes" << std::endl;
    std::cout << "Capacity: " << element_count << " blocks" << std::endl << std::endl;

    // Phase 1: Allocate blocks (internally calls pop() from free list)
    std::cout << "Phase 1: Allocating blocks (internally pop from free list)" << std::endl;
    std::vector<block_type*> blocks;

    for (size_t i = 0; i < 5; ++i) {
        block_type* ptr = allocator.allocate();
        blocks.push_back(ptr);
        std::cout << "Allocated block " << i << " at address: " << ptr << std::endl;
    }
    std::cout << std::endl;

    // Phase 2: Deallocate blocks (internally calls push() to free list)
    std::cout << "Phase 2: Deallocating blocks (internally push to free list)" << std::endl;
    std::cout << "Deallocating in order: blocks[1], blocks[3], blocks[2]" << std::endl;

    allocator.deallocate(blocks[1]);
    std::cout << "Deallocated block 1 at address: " << blocks[1] << std::endl;

    allocator.deallocate(blocks[3]);
    std::cout << "Deallocated block 3 at address: " << blocks[3] << std::endl;

    allocator.deallocate(blocks[2]);
    std::cout << "Deallocated block 2 at address: " << blocks[2] << std::endl;
    std::cout << std::endl;

    // Phase 3: Allocate again to demonstrate LIFO behavior
    std::cout << "Phase 3: Re-allocating to demonstrate LIFO (Last-In-First-Out)" << std::endl;
    std::cout << "Expected order if LIFO: blocks[2], blocks[3], blocks[1]" << std::endl;

    for (size_t i = 0; i < 3; ++i) {
        block_type* ptr = allocator.allocate();
        std::cout << "Re-allocated block at address: " << ptr;

        // Check which original block this was
        if (ptr == blocks[2]) {
            std::cout << " (was blocks[2] - deallocated last)";
        } else if (ptr == blocks[3]) {
            std::cout << " (was blocks[3] - deallocated second)";
        } else if (ptr == blocks[1]) {
            std::cout << " (was blocks[1] - deallocated first)";
        }
        std::cout << std::endl;
    }
    std::cout << std::endl;

    std::cout << "=== Key Observations ===" << std::endl;
    std::cout << "1. allocate() internally pops blocks from the head of the free list" << std::endl;
    std::cout << "2. deallocate() internally pushes blocks to the head of the free list" << std::endl;
    std::cout << "3. The free list follows LIFO (stack) behavior" << std::endl;
    std::cout << "4. Last deallocated block is first to be reallocated" << std::endl;
    std::cout << std::endl;

    std::cout << "=== Free List Internals ===" << std::endl;
    std::cout << "- push(block): Adds block to the head of the linked list" << std::endl;
    std::cout << "- pop(): Removes and returns block from the head of the linked list" << std::endl;
    std::cout << "- This provides O(1) allocation and deallocation performance" << std::endl;
}

int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
```

## Explanation

This implementation demonstrates the internal free list management of `block_allocator` through observable behavior:

1. **Phase 1 - Allocation (pop behavior)**: Allocates 5 blocks, which internally calls `pop()` to remove blocks from the free list's head.

2. **Phase 2 - Deallocation (push behavior)**: Deallocates 3 blocks in a specific order (1, 3, 2), which internally calls `push()` to add them back to the free list's head.

3. **Phase 3 - LIFO Verification**: Re-allocates 3 blocks and verifies they come back in reverse order (2, 3, 1), proving the LIFO/stack behavior of the free list.

The key insight is that while `push()` and `pop()` are private, their behavior is directly observable through `allocate()` and `deallocate()`, allowing us to understand and demonstrate the free list management mechanism.

