    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    // Get readable data size (bytes available to read)
    status.readable_size = storage.size();
    // Get free space (bytes available to write)
    status.free_space = storage.writable();
    return status;
}

template<size_t block_size = 1024>
