# Complete Implementation

```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Handle edge cases
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false; // Empty or null regions don't overlap
    }

    // Convert to char pointers for proper pointer arithmetic
    const char* src_start = static_cast<const char*>(src);
    const char* src_end = src_start + src_len;
    const char* dst_start = static_cast<const char*>(dst);
    const char* dst_end = dst_start + dst_len;

    // Two regions overlap if one starts before the other ends
    // Overlap occurs when: src_start < dst_end AND dst_start < src_end
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Handle zero-length copy as successful no-op
    if (length == 0) {
        return true;
    }

    // Validate pointers
    if (!destination || !source) {
        return false; // Invalid pointers
    }

    // Check for overlap between source and destination regions
    if (check_regions_overlap(source, length, destination, length)) {
        // Regions overlap - use memmove which handles overlapping regions safely
        std::memmove(destination, source, length);
    } else {
        // No overlap - safe to use memcpy (potentially faster)
        std::memcpy(destination, source, length);
    }

    return true; // Copy succeeded
}
```

