#include <hexi/exception.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

// Helper to proactively throw buffer_underrun when a read exceeds
// the available bytes in the adaptor.
static void ensure_can_read(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                            std::size_t length) {
    const auto available = buffer.size();
    if (length > available) {
        // For buffer_underrun exception: read_size is requested length,
        // total_read is bytes already consumed (0 for simplicity),
        // buff_size is total bytes available
        throw hexi::buffer_underrun(length, 0, available);
    }
}

UnderrunInfo catch_buffer_underrun() {
    UnderrunInfo info = {0, 0, 0, false};

    try {
        std::vector<std::byte> small_buffer(10);
        hexi::pmc::buffer_adaptor adaptor(small_buffer);

        // Attempt to read more than available to trigger underrun
        std::vector<std::byte> dest(100);
        ensure_can_read(adaptor, dest.size());
        adaptor.read(dest.data(), dest.size());
    } catch (const hexi::buffer_underrun& e) {
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.buff_size = e.buff_size;
        info.occurred = true;
    }

    return info;
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    UnderrunInfo info = {0, 0, 0, false};

    try {
        ensure_can_read(buffer, length);
        buffer.read(destination, length);
    } catch (const hexi::buffer_underrun& e) {
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.buff_size = e.buff_size;
        info.occurred = true;
    }

    return info;
}

