    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    Header header;

    // Use copy() to peek at header without advancing read cursor
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify pointer position (should still be at the beginning)
    const uint8_t* ptr = adaptor.read_ptr();

    // Verify that the pointer is still at the beginning of the buffer
    // (copy() doesn't advance the read cursor)
