    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer_read_adaptor from the vector
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

